static uint64_t rs=1;static uint32_t rnd(void){rs=rs*6364136223846793005ULL+1442695040888963407ULL;return (uint32_t)(rs>>32);}static void fill16(uint16_t*x,size_t n,uint64_t seed){rs=seed;for(size_t i=0;i<n;i++)x[i]=(uint16_t)rnd();}static void fill8(uint8_t*x,size_t n,uint64_t seed){rs=seed;for(size_t i=0;i<n;i++)x[i]=(uint8_t)rnd();}static uint64_t cksum(const uint16_t*x,size_t n){uint64_t s=1469598103934665603ULL;for(size_t i=0;i<n;i++){s^=x[i];s*=1099511628211ULL;}return s;}
static void emit(const char*ps,const char*impl,const char*profile,const char*component,const char*pass,size_t n,int rep,unsigned long long cyc,uint64_t sum,sdat_stats*st,sdat_bitreader_fast*br,int status){double cps=n?((double)cyc/(double)n):0.0;double att=(st&&st->attempts)?(double)st->attempts/n:0.0;double rej=(st&&n)?(double)st->rejections/n:0.0;double raw=(st&&n)?(double)st->random_bits/n:0.0;double cand=(st&&n&&strstr(impl,"sda"))?raw-1.0:0.0;double sign=(st&&n&&strstr(impl,"sda"))?1.0:0.0;double src=(st&&n)?(double)st->random_bytes/n:0.0;double srcbits=src*8.0;double acc=(st&&st->attempts)?(double)n/(double)st->attempts:1.0;printf("Frodo,%s,%s,%s,%s,%s,%zu,%d,%llu,%.6f,0,%.6f,%.6f,%.6f,%.6f,%.6f,%.6f,%.6f,%.9f,%llu,%u,%llu,%llu,%llu,%llu,%s\n",ps,impl,profile,component,pass,n,rep,cyc,cps,att,rej,cand,sign,raw,srcbits,src,acc,(unsigned long long)sum,br?br->available:0,br?(unsigned long long)br->bits_consumed:0,br?(unsigned long long)br->bytes_loaded:0,br?(unsigned long long)br->fast_refills:0,br?(unsigned long long)br->tail_refills:0,status?"error":"ok");}
static int run_impl(const char*impl,uint16_t*out,size_t n,const sdat_table*ot,const sdat_table*st,const uint8_t*buf,size_t blen,const uint16_t*words,size_t wc,sdat_stats*stats,sdat_bitreader_fast*br){if(!strcmp(impl,"official-original-scalar")||!strcmp(impl,"official-original-avx2")){memcpy(out,words,n*2);return strstr(impl,"avx2")?frodo_original_sample_n_avx2(out,n,ot):frodo_original_sample_n(out,n,ot);} if(!strcmp(impl,"sda-packed-scalar")||!strcmp(impl,"sda-packed-avx2")){sdat_bitreader_fast_init(br,buf,blen);return strstr(impl,"avx2")?frodo_sda_sample_n_fast_avx2(out,n,br,st,stats):frodo_sda_sample_n_fast(out,n,br,st,stats);} return strstr(impl,"avx2")?frodo_sda_word_sample_n_avx2(out,n,words,wc,st,stats):frodo_sda_word_sample_n(out,n,words,wc,st,stats);}
static void one(const char*ps,const sdat_table*ot,const sdat_table*st,size_t n,int rep){size_t blen=n*8+4096,wc=n*8+4096;uint8_t*buf=malloc(blen);uint16_t*words=malloc(wc*2),*out=malloc(n*2),*met=malloc(n*2);fill8(buf,blen,1000+rep);fill16(words,wc,2000+rep);const char*impls[]={"official-original-scalar","official-original-avx2","sda-packed-scalar","sda-packed-avx2","sda-word-scalar","sda-word-avx2"};for(size_t ii=0;ii<6;ii++){sdat_bitreader_fast br={0};unsigned long long t0=ticks();int rc=run_impl(impls[ii],out,n,ot,st,buf,blen,words,wc,0,&br);unsigned long long t1=ticks();uint64_t sum=cksum(out,n);emit(ps,impls[ii],ii<2?"original":(ii<4?"packed-bit":"word-oriented"),"full-sample-n-core","timing",n,rep,t1-t0,sum,0,&br,rc);sdat_stats stats={0};sdat_bitreader_fast br2={0};int rc2=run_impl(impls[ii],met,n,ot,st,buf,blen,words,wc,&stats,&br2);emit(ps,impls[ii],ii<2?"original":(ii<4?"packed-bit":"word-oriented"),"full-sample-n-core","metrics",n,rep,0,cksum(met,n),&stats,&br2,rc2||(sum!=cksum(met,n)));}
unsigned bits=st->random_draw_bits; sdat_bitreader_fast brc; uint32_t tmp=0; sdat_bitreader_fast_init(&brc,buf,blen); unsigned long long c0=ticks(); for(size_t i=0;i<n;i++){ if(bits==14)sdat_take_14(&brc,&tmp); else if(bits==13)sdat_take_13(&brc,&tmp); else sdat_take_7(&brc,&tmp);} unsigned long long c1=ticks(); emit(ps,"sda-packed-scalar","packed-bit","candidate-extraction-only","timing",n,rep,c1-c0,tmp,0,&brc,0);
 sdat_bitreader_fast_init(&brc,buf,blen); c0=ticks(); for(size_t i=0;i<n;i++)sdat_take_1(&brc,&tmp); c1=ticks(); emit(ps,"sda-packed-scalar","packed-bit","sign-extraction-only","timing",n,rep,c1-c0,tmp,0,&brc,0);
 sdat_bitreader_fast_init(&brc,buf,blen); c0=ticks(); for(size_t i=0;i<n;i++){ if(bits==14){do{sdat_take_14(&brc,&tmp);}while(tmp>=14534u);} else if(bits==13){do{sdat_take_13(&brc,&tmp);}while(tmp>=7442u);} else {do{sdat_take_7(&brc,&tmp);}while(tmp>=102u);} } c1=ticks(); emit(ps,"sda-packed-scalar","packed-bit","uniform-bounded-only","timing",n,rep,c1-c0,tmp,0,&brc,0);
 c0=ticks(); for(size_t i=0;i<n;i++){uint16_t x=(uint16_t)(words[i]&0x3fff); out[i]=(st->value_type==SDAT_TYPE_U8)?frodo_lookup_magnitude_scalar((uint8_t)x,st):frodo_lookup_magnitude_scalar(x,st);} c1=ticks(); emit(ps,"sda-packed-scalar","packed-bit","lookup-only","timing",n,rep,c1-c0,cksum(out,n),0,0,0);
 c0=ticks(); for(size_t i=0;i<n;i++)out[i]=frodo_apply_sign((uint16_t)(i&15),(uint8_t)(words[i]&1)); c1=ticks(); emit(ps,"sda-packed-scalar","packed-bit","sign-application-only","timing",n,rep,c1-c0,cksum(out,n),0,0,0);
 c0=ticks(); sdat_bitreader_fast_init(&brc,buf,blen); for(size_t i=0;i<n;i++){ if(bits==14)sdat_take_14(&brc,&tmp); else if(bits==13)sdat_take_13(&brc,&tmp); else sdat_take_7(&brc,&tmp);} c1=ticks(); emit(ps,"sda-packed-scalar","packed-bit","bitreader-only","timing",n,rep,c1-c0,tmp,0,&brc,0);
free(buf);free(words);free(out);free(met);} 
int main(void){puts("scheme,parameter_set,implementation,profile,component,measurement_pass,sample_count,repetition,cycles_total,cycles_per_sample,samples_per_second,attempts_per_sample,rejections_per_sample,logical_candidate_bits_per_sample,logical_sign_bits_per_sample,logical_random_bits_per_sample,source_bits_per_sample,source_bytes_per_sample,acceptance_ratio,checksum,reader_available,bits_consumed,bytes_loaded,fast_refills,tail_refills,status");const char*names[]={"frodo640","frodo976","frodo1344"};const sdat_table*o[]={&original_cdt_table_frodo640,&original_cdt_table_frodo976,&original_cdt_table_frodo1344};const sdat_table*s[]={&sda_table_frodo640,&sda_table_frodo976,&sda_table_frodo1344};size_t big[]={5120,7808,10752};for(int i=0;i<3;i++){size_t ns[]={64,big[i]};for(int ni=0;ni<2;ni++)for(int r=0;r<21;r++)one(names[i],o[i],s[i],ns[ni],r);}return 0;}
